// Validate quiz generation request
const body = $input.first().json.body;

if (!body.user_id) {
  throw new Error('Missing required field: user_id');
}

return [{
  json: {
    user_id: body.user_id,
    file_id: body.file_id || null,
    difficulty: body.difficulty || 'medium',
    num_questions: body.num_questions || 5,
    topic_focus: body.topic_focus || ''
  }
}];

// Build a summary query for context retrieval
const item = $input.first().json;

let queryText = 'Key concepts and important information';
if (item.topic_focus) {
  queryText = item.topic_focus;
}

// We need to embed this query to search Supabase
return [{
  json: {
    ...item,
    query_text: queryText
  }
}];

// Prepare vector search RPC call for Supabase
const embeddingRaw = $input.first().json.data || $input.first().json;
const prevData = $('Build: Search Query').first().json;

let embedding;
if (Array.isArray(embeddingRaw) && Array.isArray(embeddingRaw[0])) {
  embedding = embeddingRaw[0];
} else if (Array.isArray(embeddingRaw)) {
  embedding = embeddingRaw;
}

return [{
  json: {
    ...prevData,
    query_embedding: embedding
  }
}];

// Assemble context from search results and build LLM prompt
const searchResults = $input.first().json;
const quizParams = $('Validate: Quiz Request').first().json;

// searchResults might be an array at top level
const results = Array.isArray(searchResults) ? searchResults : 
                (searchResults.data ? searchResults.data : [searchResults]);

// Build context from retrieved chunks
const context = results
  .map((r, i) => `[Chunk ${i+1} — ${r.file_name || 'Unknown'}]\n${r.content}`)
  .join('\n\n---\n\n');

if (context.length < 50) {
  throw new Error('No relevant content found for quiz generation. Please upload study materials first.');
}

const difficultyGuide = {
  easy: 'Basic recall and comprehension questions. Use simple language. Focus on definitions and key facts.',
  medium: 'Application and analysis questions. Test understanding of concepts and relationships between ideas.',
  hard: 'Synthesis and evaluation questions. Require deep understanding, critical thinking, and ability to connect multiple concepts.'
};

const prompt = `You are an expert educator creating a quiz based on the following study material.

STUDY MATERIAL:
${context}

DIFFICULTY: ${quizParams.difficulty}
GUIDELINES: ${difficultyGuide[quizParams.difficulty] || difficultyGuide.medium}
NUMBER OF QUESTIONS: ${quizParams.num_questions}
${quizParams.topic_focus ? 'FOCUS TOPIC: ' + quizParams.topic_focus : ''}

Generate exactly ${quizParams.num_questions} multiple-choice questions. Each question should have 4 options (A, B, C, D) with exactly one correct answer.

Respond ONLY with valid JSON in this exact format:
{
  "questions": [
    {
      "id": 1,
      "question": "...",
      "options": {
        "A": "...",
        "B": "...",
        "C": "...",
        "D": "..."
      },
      "correct_answer": "A",
      "explanation": "Brief explanation of why this is correct",
      "topic": "The topic this question covers",
      "difficulty": "${quizParams.difficulty}"
    }
  ]
}`;

return [{
  json: {
    ...quizParams,
    context_length: context.length,
    chunks_used: results.length,
    llm_prompt: prompt
  }
}];

// Parse Groq response and format quiz
const groqResponse = $input.first().json;
const quizParams = $('Validate: Quiz Request').first().json;

let quizData;
try {
  const content = groqResponse.choices[0].message.content;
  quizData = JSON.parse(content);
} catch (e) {
  throw new Error('Failed to parse quiz from LLM: ' + e.message);
}

return [{
  json: {
    success: true,
    quiz: {
      quiz_id: `quiz_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`,
      user_id: quizParams.user_id,
      file_id: quizParams.file_id,
      difficulty: quizParams.difficulty,
      num_questions: quizData.questions?.length || 0,
      questions: quizData.questions || [],
      generated_at: new Date().toISOString()
    }
  }
}];

// Validate and process quiz evaluation request
const body = $input.first().json.body;

if (!body.user_id || !body.questions || !body.user_answers) {
  throw new Error('Missing required fields: user_id, questions, user_answers');
}

const questions = body.questions;
const userAnswers = body.user_answers;

// Score the quiz
let correct = 0;
let incorrect = 0;
const results = [];
const weakTopics = [];

for (let i = 0; i < questions.length; i++) {
  const q = questions[i];
  const userAnswer = userAnswers[i] || '';
  const isCorrect = userAnswer.toUpperCase() === q.correct_answer.toUpperCase();

  if (isCorrect) {
    correct++;
  } else {
    incorrect++;
    weakTopics.push(q.topic || `Question ${i+1}`);
  }

  results.push({
    question_id: q.id,
    question: q.question,
    user_answer: userAnswer,
    correct_answer: q.correct_answer,
    is_correct: isCorrect,
    explanation: q.explanation || '',
    topic: q.topic || ''
  });
}

return [{
  json: {
    user_id: body.user_id,
    file_id: body.file_id || null,
    difficulty: body.difficulty || 'medium',
    total_questions: questions.length,
    correct_answers: correct,
    incorrect_answers: incorrect,
    score_percentage: Math.round((correct / questions.length) * 100),
    results: results,
    weak_topics: [...new Set(weakTopics)],  // deduplicate
    questions: questions,
    user_answers: userAnswers
  }
}];

// Build gap analysis prompt
const scored = $input.first().json;

if (scored.incorrect_answers === 0) {
  // Perfect score — skip LLM call
  return [{
    json: {
      ...scored,
      gap_analysis: {
        summary: 'Excellent! You answered all questions correctly.',
        knowledge_gaps: [],
        recommendations: ['Continue with harder difficulty to challenge yourself.'],
        mastery_level: 'Expert'
      }
    }
  }];
}

const wrongAnswers = scored.results
  .filter(r => !r.is_correct)
  .map(r => `Q: ${r.question}\nYour Answer: ${r.user_answer} | Correct: ${r.correct_answer}\nTopic: ${r.topic}\nExplanation: ${r.explanation}`)
  .join('\n\n');

const prompt = `You are a learning analytics expert. Analyze the following incorrect quiz answers and provide a detailed concept gap analysis.

STUDENT PERFORMANCE:
- Score: ${scored.correct_answers}/${scored.total_questions} (${scored.score_percentage}%)
- Difficulty: ${scored.difficulty}

INCORRECT ANSWERS:
${wrongAnswers}

WEAK TOPICS IDENTIFIED: ${scored.weak_topics.join(', ')}

Provide a JSON response with this structure:
{
  "summary": "2-3 sentence overview of the student's understanding gaps",
  "knowledge_gaps": [
    {
      "topic": "Topic name",
      "gap_description": "What the student doesn't understand",
      "severity": "high/medium/low",
      "prerequisite_concepts": ["concepts they should review first"]
    }
  ],
  "recommendations": [
    "Specific actionable study recommendations"
  ],
  "suggested_resources": [
    "Types of resources that would help (e.g., 'Watch a video on X', 'Read chapter about Y')"
  ],
  "mastery_level": "Beginner/Intermediate/Advanced/Expert",
  "next_steps": "What difficulty and topics to focus on next"
}`;

return [{
  json: {
    ...scored,
    needs_gap_analysis: true,
    gap_prompt: prompt
  }
}];

// Parse gap analysis and combine with quiz results
const groqResponse = $input.first().json;
const quizData = $('Build: Gap Analysis Prompt').first().json;

let gapAnalysis;
try {
  const content = groqResponse.choices[0].message.content;
  gapAnalysis = JSON.parse(content);
} catch (e) {
  gapAnalysis = {
    summary: 'Gap analysis could not be parsed. Review incorrect answers manually.',
    knowledge_gaps: quizData.weak_topics.map(t => ({ topic: t, severity: 'medium' })),
    recommendations: ['Review the topics you got wrong.'],
    mastery_level: quizData.score_percentage >= 70 ? 'Intermediate' : 'Beginner'
  };
}

return [{
  json: {
    success: true,
    evaluation: {
      user_id: quizData.user_id,
      file_id: quizData.file_id,
      score: {
        correct: quizData.correct_answers,
        total: quizData.total_questions,
        percentage: quizData.score_percentage
      },
      difficulty: quizData.difficulty,
      results: quizData.results,
      gap_analysis: gapAnalysis,
      evaluated_at: new Date().toISOString()
    }
  }
}];

// Perfect score — just format the response
const data = $input.first().json;

return [{
  json: {
    success: true,
    evaluation: {
      user_id: data.user_id,
      file_id: data.file_id,
      score: {
        correct: data.correct_answers,
        total: data.total_questions,
        percentage: data.score_percentage
      },
      difficulty: data.difficulty,
      results: data.results,
      gap_analysis: data.gap_analysis,
      evaluated_at: new Date().toISOString()
    }
  }
}];
